/* CR0901M01.updateLgistCompl - 물류완료 처리 */
UPDATE TB_CR11M01
SET    LGIST_COMPL_YN   = 'Y'
     , LGIST_COMPL_DTTM = SYSDATE
     , UDT_ID           = #{userId}
     , UDT_DTTM         = SYSDATE
WHERE  LGIST_NO         = #{lgistNo}

/* CR0901M01.cancelLgistCompl - 물류완료 취소 처리 */
UPDATE TB_CR11M01
SET    LGIST_COMPL_YN   = 'N'
     , LGIST_COMPL_DTTM = NULL
     , UDT_ID           = #{userId}
     , UDT_DTTM         = SYSDATE
WHERE  LGIST_NO         = #{lgistNo}
